/**
 * @posthog/sdk resource-layer emitter.
 *
 * Inputs (committed MCP codegen artifacts, regenerated by `hogli build:openapi`):
 *   - services/mcp/schema/generated-tool-definitions.json  (tool metadata, JSDoc)
 *   - services/mcp/src/tools/generated/*.ts                (tool handlers — parsed)
 *   - services/mcp/src/generated/<module>/api.ts           (Orval Zod input schemas)
 *   - services/mcp/src/api/generated.ts                    (Schemas namespace — responses)
 *
 * Outputs (committed) under packages/sdk/src/generated/:
 *   - schemas.ts            (vendored Schemas namespace — response/component types)
 *   - inputs.ts             (plain-TS request types, materialized from Zod → JSON Schema)
 *   - resources/<name>.ts   (one class per resource)
 *   - client.ts             (PostHogClient composing all resources)
 *
 * Runtime Zod is never emitted: input types are materialized to plain TS at
 * generate time via z.toJSONSchema(). Zod is a devDependency of this package.
 */
import { spawnSync } from 'node:child_process'
import * as fs from 'node:fs'
import { createRequire } from 'node:module'
import * as path from 'node:path'
import { fileURLToPath } from 'node:url'
import ts from 'typescript'
import { z } from 'zod'

const require = createRequire(import.meta.url)
const __dirname = path.dirname(fileURLToPath(import.meta.url))
const SDK_ROOT = path.resolve(__dirname, '..')
const MCP_ROOT = path.resolve(SDK_ROOT, '../../services/mcp')
const OUT_DIR = path.join(SDK_ROOT, 'src/generated')

const TOOL_DEFS_PATH = path.join(MCP_ROOT, 'schema/generated-tool-definitions.json')
const TOOLS_DIR = path.join(MCP_ROOT, 'src/tools/generated')
const SCHEMAS_SRC = path.join(MCP_ROOT, 'src/api/generated.ts')

// ---------------------------------------------------------------------------
// Naming: tool-name (`domain-action`) → resource.method
// ---------------------------------------------------------------------------

// Longest-first. Maps a trailing action segment-phrase to a canonical verb.
const ACTION_SUFFIXES: Array<[string, string]> = [
    ['partial-update', 'update'],
    ['get-definition', 'get'],
    ['get-all', 'list'],
    ['list', 'list'],
    ['create', 'create'],
    ['retrieve', 'get'],
    ['destroy', 'delete'],
    ['delete', 'delete'],
    ['update', 'update'],
    ['get', 'get'],
]

// Canonicalize singular/legacy resource kebabs to their published plural form.
const RESOURCE_ALIASES: Record<string, string> = {
    'feature-flag': 'feature-flags',
    dashboard: 'dashboards',
    insight: 'insights',
    experiment: 'experiments',
    action: 'actions',
    annotation: 'annotations',
    survey: 'surveys',
    alert: 'alerts',
    cohort: 'cohorts',
    person: 'persons',
    notebook: 'notebooks',
}

// Legacy verb-first tool names that the suffix rule can't split.
const TOOL_OVERRIDES: Record<string, { resource: string; method: string }> = {
    'create-feature-flag': { resource: 'feature-flags', method: 'create' },
    'update-feature-flag': { resource: 'feature-flags', method: 'update' },
    'delete-feature-flag': { resource: 'feature-flags', method: 'delete' },
    'feature-flag-get-all': { resource: 'feature-flags', method: 'list' },
    'feature-flag-get-definition': { resource: 'feature-flags', method: 'get' },
}

function aliasResource(kebab: string): string {
    return RESOURCE_ALIASES[kebab] ?? kebab
}

function camelCase(kebab: string): string {
    const parts = kebab.split('-').filter(Boolean)
    return parts
        .map((p, i) => (i === 0 ? p : p.charAt(0).toUpperCase() + p.slice(1)))
        .join('')
        .replace(/[^a-zA-Z0-9]/g, '')
}

function pascalCase(kebab: string): string {
    const c = camelCase(kebab)
    return c.charAt(0).toUpperCase() + c.slice(1)
}

/** Splits a tool name into action verb + base segments (resource + extra). */
function splitAction(name: string): { actionWord: string; baseSegs: string[] } {
    for (const [suffix, verb] of ACTION_SUFFIXES) {
        if (name === suffix) {
            return { actionWord: verb, baseSegs: [] }
        }
        if (name.endsWith('-' + suffix)) {
            const base = name.slice(0, -(suffix.length + 1))
            return { actionWord: verb, baseSegs: base.split('-') }
        }
    }
    const segs = name.split('-')
    return { actionWord: segs[segs.length - 1]!, baseSegs: segs.slice(0, -1) }
}

// ---------------------------------------------------------------------------
// Parse generated tool handlers with the TypeScript compiler API
// ---------------------------------------------------------------------------

interface ParsedTool {
    name: string
    method: string
    /** Transformed source of the request-call argument object (path/method/body/query). */
    requestArgText: string
    /** Transformed prelude statements (scope resolution + body/query construction). */
    preludeText: string
    responseType: string
    /** `params.X` field names referenced anywhere in the handler. */
    referencedParamFields: Set<string>
    /** Zod schema identifiers (resolved through local consts) feeding the input. */
    referencedSchemas: Array<{ module: string; ident: string }>
    omittedKeys: Set<string>
    inlineExtendKeys: Set<string>
}

/**
 * Rewrite MCP handler source into SDK method source:
 *  - stateManager scope calls → this.scope.* (original LHS var name preserved)
 *  - runtime `SomeSchema.parse(params)` → `params` (the SDK does no runtime validation)
 */
function transformHandlerText(text: string): string {
    return text
        .replaceAll('context.stateManager.getProjectId()', 'this.scope.projectId(opts)')
        .replaceAll('context.stateManager.getOrgID()', 'this.scope.organizationId(opts)')
        .replace(/\b[A-Za-z_$][\w$]*Schema\.parse\(/g, '(')
}

function collectParamFields(text: string, out: Set<string>): void {
    for (const m of text.matchAll(/params\.([A-Za-z_$][\w$]*)/g)) {
        out.add(m[1]!)
    }
    for (const m of text.matchAll(/params\[['"]([^'"]+)['"]\]/g)) {
        out.add(m[1]!)
    }
}

interface SkippedTool {
    name: string
    reason: string
}

function collectIdentifiers(node: ts.Node, out: Set<string>): void {
    if (ts.isIdentifier(node)) {
        out.add(node.text)
    }
    node.forEachChild((c) => collectIdentifiers(c, out))
}

function collectOmitAndExtend(node: ts.Node, omitted: Set<string>, extended: Set<string>): void {
    if (ts.isCallExpression(node) && ts.isPropertyAccessExpression(node.expression)) {
        const method = node.expression.name.text
        const arg = node.arguments[0]
        if (method === 'omit' && arg && ts.isObjectLiteralExpression(arg)) {
            for (const p of arg.properties) {
                if (p.name && (ts.isIdentifier(p.name) || ts.isStringLiteral(p.name))) {
                    omitted.add(p.name.text)
                }
            }
        }
        if (method === 'extend' && arg && ts.isObjectLiteralExpression(arg)) {
            for (const p of arg.properties) {
                if (p.name && (ts.isIdentifier(p.name) || ts.isStringLiteral(p.name))) {
                    extended.add(p.name.text)
                }
            }
        }
    }
    node.forEachChild((c) => collectOmitAndExtend(c, omitted, extended))
}

function findRequestCall(node: ts.Node): ts.CallExpression[] {
    const found: ts.CallExpression[] = []
    const visit = (n: ts.Node): void => {
        if (
            ts.isCallExpression(n) &&
            ts.isPropertyAccessExpression(n.expression) &&
            n.expression.name.text === 'request' &&
            ts.isPropertyAccessExpression(n.expression.expression) &&
            n.expression.expression.name.text === 'api'
        ) {
            found.push(n)
        }
        n.forEachChild(visit)
    }
    visit(node)
    return found
}

function parseToolFile(
    filePath: string,
    zodImportsIndex: Map<string, string>,
    tools: ParsedTool[],
    skipped: SkippedTool[]
): void {
    const src = fs.readFileSync(filePath, 'utf8')
    const sf = ts.createSourceFile(filePath, src, ts.ScriptTarget.Latest, true)

    // Map: zod ident imported in this file → module path (e.g. 'feature_flags').
    const zodImports = new Map<string, string>()
    // Map: local const name → initializer node (for schema resolution).
    const localConsts = new Map<string, ts.Expression>()

    const collectTop = (node: ts.Node): void => {
        if (ts.isImportDeclaration(node) && node.importClause?.namedBindings) {
            const spec = (node.moduleSpecifier as ts.StringLiteral).text
            const m = /^@\/generated\/([^/]+)\/api$/.exec(spec)
            if (m && ts.isNamedImports(node.importClause.namedBindings)) {
                for (const el of node.importClause.namedBindings.elements) {
                    zodImports.set(el.name.text, m[1]!)
                }
            }
        }
        if (ts.isVariableStatement(node)) {
            for (const d of node.declarationList.declarations) {
                if (ts.isIdentifier(d.name) && d.initializer) {
                    localConsts.set(d.name.text, d.initializer)
                }
            }
        }
        node.forEachChild(collectTop)
    }
    collectTop(sf)

    // Resolve a schema expression: follow local const references, collect the
    // Zod import idents it references plus its omit/extend keys.
    function analyzeSchema(expr: ts.Expression): {
        referenced: Array<{ module: string; ident: string }>
        omitted: Set<string>
        extended: Set<string>
    } {
        const idents = new Set<string>()
        const omitted = new Set<string>()
        const extended = new Set<string>()
        const seen = new Set<string>()
        const walk = (e: ts.Expression): void => {
            const local = new Set<string>()
            collectIdentifiers(e, local)
            collectOmitAndExtend(e, omitted, extended)
            for (const id of local) {
                if (zodImports.has(id)) {
                    idents.add(id)
                } else if (localConsts.has(id) && !seen.has(id)) {
                    seen.add(id)
                    walk(localConsts.get(id)!)
                }
            }
        }
        walk(expr)
        const referenced = [...idents].sort().map((ident) => ({ module: zodImports.get(ident)!, ident }))
        return { referenced, omitted, extended }
    }

    // Walk for tool object literals: `{ name: '...', schema: ..., handler: async (context, params) => {...} }`
    const visit = (node: ts.Node): void => {
        if (ts.isObjectLiteralExpression(node)) {
            const nameProp = node.properties.find(
                (p): p is ts.PropertyAssignment =>
                    ts.isPropertyAssignment(p) && p.name.getText(sf) === 'name' && ts.isStringLiteral(p.initializer)
            )
            const handlerProp = node.properties.find(
                (p): p is ts.PropertyAssignment => ts.isPropertyAssignment(p) && p.name.getText(sf) === 'handler'
            )
            const schemaProp = node.properties.find(
                (p): p is ts.PropertyAssignment => ts.isPropertyAssignment(p) && p.name.getText(sf) === 'schema'
            )
            if (nameProp && handlerProp) {
                const toolName = (nameProp.initializer as ts.StringLiteral).text
                try {
                    parseTool(toolName, handlerProp.initializer, schemaProp?.initializer, sf, analyzeSchema, tools)
                } catch (e) {
                    skipped.push({ name: toolName, reason: (e as Error).message })
                }
                return // don't descend into a matched tool object
            }
        }
        node.forEachChild(visit)
    }
    visit(sf)
    // Merge this file's zod imports into the global index for module resolution.
    for (const [ident, mod] of zodImports) {
        zodImportsIndex.set(`${mod}:${ident}`, mod)
    }
}

function parseTool(
    name: string,
    handler: ts.Expression,
    schemaExpr: ts.Expression | undefined,
    sf: ts.SourceFile,
    analyzeSchema: (e: ts.Expression) => {
        referenced: Array<{ module: string; ident: string }>
        omitted: Set<string>
        extended: Set<string>
    },
    tools: ParsedTool[]
): void {
    if (!ts.isArrowFunction(handler) && !ts.isFunctionExpression(handler)) {
        throw new Error('handler is not a function')
    }
    const body = handler.body
    if (!body || !ts.isBlock(body)) {
        throw new Error('handler has no block body')
    }
    const requests = findRequestCall(body)
    if (requests.length === 0) {
        throw new Error('no context.api.request call (hand-written factory)')
    }
    if (requests.length > 1) {
        throw new Error(`${requests.length} request calls — not a simple 1:1 handler`)
    }
    const call = requests[0]!
    const typeArg = call.typeArguments?.[0]
    const responseType = typeArg ? unwrapResponseType(typeArg.getText(sf)) : 'unknown'
    const argObj = call.arguments[0]
    if (!argObj || !ts.isObjectLiteralExpression(argObj)) {
        throw new Error('request arg is not an object literal')
    }

    const fullSrc = sf.getFullText()
    const requestArgText = transformHandlerText(fullSrc.slice(argObj.getStart(sf), argObj.getEnd()))

    // Method literal from the request arg.
    const methodProp = argObj.properties.find(
        (p): p is ts.PropertyAssignment => ts.isPropertyAssignment(p) && p.name.getText(sf) === 'method'
    )
    const method = methodProp && ts.isStringLiteral(methodProp.initializer) ? methodProp.initializer.text : undefined
    if (!method) {
        throw new Error('non-literal HTTP method')
    }

    // Prelude = the scope-resolution and body/query-construction statements that
    // appear BEFORE the request call. Statements at or after the request (result
    // post-processing, withPostHogUrl/pickResponseFields wrapping) are dropped —
    // the SDK returns the raw API response. Emitted with handler transforms.
    const statements = body.statements
    const reqIndex = statements.findIndex((s) =>
        fullSrc.slice(s.getStart(sf), s.getEnd()).includes('context.api.request')
    )
    const preludeParts: string[] = []
    for (let i = 0; i < (reqIndex >= 0 ? reqIndex : statements.length); i++) {
        const stmt = statements[i]!
        const text = transformHandlerText(fullSrc.slice(stmt.getStart(sf), stmt.getEnd()))
        if (text.includes('context.')) {
            throw new Error('prelude references context beyond stateManager')
        }
        preludeParts.push(text)
    }
    const preludeText = preludeParts.join('\n')

    const referencedParamFields = new Set<string>()
    collectParamFields(preludeText, referencedParamFields)
    collectParamFields(requestArgText, referencedParamFields)

    const schemaInfo = schemaExpr
        ? analyzeSchema(schemaExpr)
        : { referenced: [], omitted: new Set<string>(), extended: new Set<string>() }

    tools.push({
        name,
        method,
        requestArgText,
        preludeText,
        responseType,
        referencedParamFields,
        referencedSchemas: schemaInfo.referenced,
        omittedKeys: schemaInfo.omitted,
        inlineExtendKeys: schemaInfo.extended,
    })
}

/** Strip MCP-only response wrappers so the SDK returns the raw API type. */
function unwrapResponseType(text: string): string {
    let t = text.trim()
    const m = /^WithPostHogUrl<([\s\S]+)>$/.exec(t)
    if (m) {
        t = m[1]!.trim()
    }
    return t
}

// ---------------------------------------------------------------------------
// Query wrapper tools (`createQueryWrapper` factories)
// ---------------------------------------------------------------------------
//
// The `query-*` tools are not 1:1 request handlers: a shared factory
// (services/mcp/src/tools/query-wrapper-factory.ts) injects `kind` into the
// params and POSTs to /api/environments/{projectId}/query/ (actors kinds get
// wrapped in an ActorsQuery first). The runtime semantics live in the
// handwritten `src/core/query.ts` (QueryBase); here we parse each
// `createQueryWrapper({ name, schema, kind })` call and evaluate its Zod
// schema — the schemas are file-local consts, so we extract their declaration
// closure into a temp module and import it.

interface WrapperTool {
    name: string
    kind: string
    methodName: string
    schema: z.ZodType
}

function parseQueryWrappers(files: string[]): WrapperTool[] {
    const wrappers: WrapperTool[] = []
    const tmpDir = path.join(SDK_ROOT, '.tmp-generate-query-wrappers')
    fs.rmSync(tmpDir, { recursive: true, force: true })
    fs.mkdirSync(tmpDir, { recursive: true })
    try {
        for (const f of files.sort()) {
            const filePath = path.join(TOOLS_DIR, f)
            const src = fs.readFileSync(filePath, 'utf8')
            if (!src.includes('createQueryWrapper(')) {
                continue
            }
            wrappers.push(...parseQueryWrapperFile(filePath, src, tmpDir))
        }
    } finally {
        fs.rmSync(tmpDir, { recursive: true, force: true })
    }
    wrappers.sort((a, b) => a.name.localeCompare(b.name))
    return wrappers
}

function parseQueryWrapperFile(filePath: string, src: string, tmpDir: string): WrapperTool[] {
    const sf = ts.createSourceFile(filePath, src, ts.ScriptTarget.Latest, true)
    const fullSrc = sf.getFullText()

    // Top-level const declarations (name → { initializer, statement text, order }).
    const localConsts = new Map<string, { init: ts.Expression; text: string; order: number }>()
    // Imported identifiers → module specifier.
    const importSpecs = new Map<string, string>()
    let order = 0
    sf.forEachChild((node) => {
        if (ts.isVariableStatement(node)) {
            for (const d of node.declarationList.declarations) {
                if (ts.isIdentifier(d.name) && d.initializer) {
                    localConsts.set(d.name.text, {
                        init: d.initializer,
                        text: fullSrc.slice(node.getStart(sf), node.getEnd()),
                        order: order++,
                    })
                }
            }
        }
        if (ts.isImportDeclaration(node) && node.importClause?.namedBindings) {
            const spec = (node.moduleSpecifier as ts.StringLiteral).text
            const nb = node.importClause.namedBindings
            if (ts.isNamedImports(nb)) {
                for (const el of nb.elements) {
                    importSpecs.set(el.name.text, spec)
                }
            }
        }
    })

    // Collect createQueryWrapper({ name, schema, kind }) calls.
    const calls: Array<{ name: string; kind: string; schemaExpr: ts.Expression }> = []
    const visit = (n: ts.Node): void => {
        if (ts.isCallExpression(n) && ts.isIdentifier(n.expression) && n.expression.text === 'createQueryWrapper') {
            const arg = n.arguments[0]
            if (!arg || !ts.isObjectLiteralExpression(arg)) {
                throw new Error(`createQueryWrapper call without object literal in ${filePath}`)
            }
            const get = (key: string): ts.Expression | undefined =>
                arg.properties.find(
                    (p): p is ts.PropertyAssignment => ts.isPropertyAssignment(p) && p.name.getText(sf) === key
                )?.initializer
            const nameExpr = get('name')
            const kindExpr = get('kind')
            const schemaExpr = get('schema')
            if (
                !nameExpr ||
                !ts.isStringLiteral(nameExpr) ||
                !kindExpr ||
                !ts.isStringLiteral(kindExpr) ||
                !schemaExpr
            ) {
                throw new Error(`createQueryWrapper call with non-literal name/kind in ${filePath}`)
            }
            calls.push({ name: nameExpr.text, kind: kindExpr.text, schemaExpr })
        }
        n.forEachChild(visit)
    }
    visit(sf)
    if (calls.length === 0) {
        return []
    }

    // Declaration closure of the schema expressions over file-local consts.
    const closure = new Set<string>()
    const seen = new Set<string>()
    const expand = (id: string): void => {
        if (seen.has(id)) {
            return
        }
        seen.add(id)
        const local = localConsts.get(id)
        if (local) {
            closure.add(id)
            const ids = new Set<string>()
            collectIdentifiers(local.init, ids)
            for (const ref of ids) {
                expand(ref)
            }
            return
        }
        const spec = importSpecs.get(id)
        if (spec && spec !== 'zod') {
            throw new Error(`query wrapper schema in ${filePath} references non-zod import '${id}' from '${spec}'`)
        }
    }
    for (const call of calls) {
        const ids = new Set<string>()
        collectIdentifiers(call.schemaExpr, ids)
        for (const id of ids) {
            expand(id)
        }
    }

    // Emit a temp module: zod import + closure consts in source order + schema map.
    const closureStatements = [...closure]
        .map((id) => localConsts.get(id)!)
        .sort((a, b) => a.order - b.order)
        .map((c) => c.text)
    const mapEntries = calls.map((c) => `    ${JSON.stringify(c.name)}: (${c.schemaExpr.getText(sf)}),`).join('\n')
    const moduleText = [
        `import { z } from 'zod'`,
        '',
        ...closureStatements,
        '',
        `export const __WRAPPER_SCHEMAS: Record<string, unknown> = {`,
        mapEntries,
        `}`,
        '',
    ].join('\n')
    const tmpFile = path.join(tmpDir, `${path.basename(filePath, '.ts')}.eval.ts`)
    fs.writeFileSync(tmpFile, moduleText)
    const mod = require(tmpFile) as { __WRAPPER_SCHEMAS: Record<string, unknown> }

    return calls.map((c) => {
        const schema = mod.__WRAPPER_SCHEMAS[c.name]
        if (!schema || typeof schema !== 'object' || !('_def' in (schema as object))) {
            throw new Error(`evaluated schema for ${c.name} is not a Zod schema`)
        }
        return {
            name: c.name,
            kind: c.kind,
            methodName: camelCase(c.name.replace(/^query-/, '')),
            schema: schema as z.ZodType,
        }
    })
}

// ---------------------------------------------------------------------------
// Input types: Zod schema → JSON Schema → plain TS
// ---------------------------------------------------------------------------

interface JsonSchema {
    type?: string | string[]
    properties?: Record<string, JsonSchema>
    required?: string[]
    items?: JsonSchema
    anyOf?: JsonSchema[]
    enum?: unknown[]
    const?: unknown
    additionalProperties?: boolean | JsonSchema
    description?: string
    format?: string
}

const DROP_FIELDS = new Set(['project_id', 'organization_id'])

function loadZodModule(moduleName: string): Record<string, unknown> {
    const modPath = path.join(MCP_ROOT, 'src/generated', moduleName, 'api.ts')
    // tsx registers a loader; require works for these ESM-authored TS modules
    // through the tsx runtime used to execute this script.
    return require(modPath) as Record<string, unknown>
}

const zodModuleCache = new Map<string, Record<string, unknown>>()
function getZodSchema(moduleName: string, ident: string): z.ZodType | undefined {
    let mod = zodModuleCache.get(moduleName)
    if (!mod) {
        mod = loadZodModule(moduleName)
        zodModuleCache.set(moduleName, mod)
    }
    const val = mod[ident]
    return val && typeof val === 'object' && '_def' in (val as object) ? (val as z.ZodType) : undefined
}

/** Merge referenced Zod schemas into one flat property map (the method input). */
function buildInputSchema(tool: ParsedTool): { properties: Record<string, JsonSchema>; required: Set<string> } {
    const properties: Record<string, JsonSchema> = {}
    const required = new Set<string>()
    for (const { module, ident } of tool.referencedSchemas) {
        const schema = getZodSchema(module, ident)
        if (!schema) {
            continue
        }
        const js = z.toJSONSchema(schema, { unrepresentable: 'any', io: 'input' }) as JsonSchema
        if (js.type !== 'object' || !js.properties) {
            continue
        }
        for (const [key, val] of Object.entries(js.properties)) {
            if (DROP_FIELDS.has(key) || tool.omittedKeys.has(key)) {
                continue
            }
            if (!(key in properties)) {
                properties[key] = val
            }
        }
        for (const key of js.required ?? []) {
            if (!DROP_FIELDS.has(key) && !tool.omittedKeys.has(key)) {
                required.add(key)
            }
        }
    }
    // Inline `.extend({...})` keys and any `params.X` the handler references that
    // we couldn't type from a schema: fall back to `unknown` (weaker but sound).
    for (const key of [...tool.inlineExtendKeys, ...tool.referencedParamFields]) {
        if (!(key in properties) && !DROP_FIELDS.has(key)) {
            properties[key] = { type: 'object', __unknown: true } as JsonSchema & { __unknown: boolean }
        }
    }
    return { properties, required }
}

// `output_format` is an MCP tool-level response control, not query input.
const WRAPPER_DROP_FIELDS = new Set(['output_format'])

/**
 * Input schema for a query wrapper method: the evaluated Zod schema on its
 * INPUT side (pre-parse — coercions/defaults leave fields optional), minus
 * MCP-only controls.
 */
function buildWrapperInputSchema(schema: z.ZodType): { properties: Record<string, JsonSchema>; required: Set<string> } {
    const js = z.toJSONSchema(schema, { unrepresentable: 'any', io: 'input' }) as JsonSchema
    const properties: Record<string, JsonSchema> = {}
    const required = new Set<string>()
    for (const [key, val] of Object.entries(js.properties ?? {})) {
        if (!WRAPPER_DROP_FIELDS.has(key)) {
            properties[key] = val
        }
    }
    for (const key of js.required ?? []) {
        if (!WRAPPER_DROP_FIELDS.has(key)) {
            required.add(key)
        }
    }
    return { properties, required }
}

/** Render a JSON Schema node as a TypeScript type expression. */
function tsType(schema: JsonSchema, indent: string): string {
    if ((schema as JsonSchema & { __unknown?: boolean }).__unknown) {
        return 'unknown'
    }
    if (schema.const !== undefined) {
        return JSON.stringify(schema.const)
    }
    if (schema.anyOf && schema.anyOf.length > 0) {
        const parts = schema.anyOf.map((s) => tsType(s, indent))
        return [...new Set(parts)].join(' | ')
    }
    if (schema.enum && schema.enum.length > 0) {
        return schema.enum.map((v) => JSON.stringify(v)).join(' | ')
    }
    const type = Array.isArray(schema.type) ? schema.type : schema.type ? [schema.type] : []
    if (type.length > 1) {
        return type.map((t) => tsType({ ...schema, type: t }, indent)).join(' | ')
    }
    const single = type[0]
    switch (single) {
        case 'string':
            return 'string'
        case 'number':
        case 'integer':
            return 'number'
        case 'boolean':
            return 'boolean'
        case 'null':
            return 'null'
        case 'array':
            return `Array<${schema.items ? tsType(schema.items, indent) : 'unknown'}>`
        case 'object': {
            if (schema.properties && Object.keys(schema.properties).length > 0) {
                return renderObject(schema, indent)
            }
            if (schema.additionalProperties && typeof schema.additionalProperties === 'object') {
                return `Record<string, ${tsType(schema.additionalProperties, indent)}>`
            }
            if (schema.additionalProperties === false) {
                return 'Record<string, never>'
            }
            return 'Record<string, unknown>'
        }
        default:
            return 'unknown'
    }
}

function renderObject(schema: JsonSchema, indent: string): string {
    const props = schema.properties ?? {}
    const req = new Set(schema.required ?? [])
    const inner = indent + '    '
    const lines: string[] = []
    for (const key of Object.keys(props).sort()) {
        const val = props[key]!
        const optional = req.has(key) ? '' : '?'
        const desc = val.description ? `${inner}/** ${escapeComment(val.description)} */\n` : ''
        lines.push(`${desc}${inner}${quoteKey(key)}${optional}: ${tsType(val, inner)}`)
    }
    return `{\n${lines.join('\n')}\n${indent}}`
}

function quoteKey(key: string): string {
    return /^[A-Za-z_$][A-Za-z0-9_$]*$/.test(key) ? key : JSON.stringify(key)
}

function escapeComment(text: string): string {
    return text.replace(/\*\//g, '*\\/').replace(/\s+/g, ' ').trim()
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

interface ResolvedMethod {
    method: string
    /** Set for methods parsed from a standard 1:1 request handler. */
    tool?: ParsedTool
    /** Set for methods emitted from a `createQueryWrapper` factory. */
    wrapper?: WrapperTool
    inputTypeName: string | undefined
    inputRequired: boolean
    jsdoc: string
}

function main(): void {
    const toolDefs = JSON.parse(fs.readFileSync(TOOL_DEFS_PATH, 'utf8')) as Record<string, { description?: string }>
    const files = fs
        .readdirSync(TOOLS_DIR)
        .filter((f) => f.endsWith('.ts') && f !== 'index.ts')
        .sort()

    const tools: ParsedTool[] = []
    const skipped: SkippedTool[] = []
    const zodImportsIndex = new Map<string, string>()
    for (const f of files) {
        parseToolFile(path.join(TOOLS_DIR, f), zodImportsIndex, tools, skipped)
    }
    tools.sort((a, b) => a.name.localeCompare(b.name))

    // --- Resource / method assignment (two passes for known-resource discovery) ---
    // Count every segment-prefix of every tool's base. A prefix shared by >=2
    // tools is treated as a resource, so compound tools (e.g. integrations-channels-list)
    // group under their shared root (integrations) instead of fragmenting.
    const prefixFrequency = new Map<string, number>()
    for (const t of tools) {
        if (TOOL_OVERRIDES[t.name]) {
            continue
        }
        const { baseSegs } = splitAction(t.name)
        for (let l = 1; l <= baseSegs.length; l++) {
            const prefix = baseSegs.slice(0, l).join('-')
            prefixFrequency.set(prefix, (prefixFrequency.get(prefix) ?? 0) + 1)
        }
    }
    const knownResources = new Set<string>([...Object.keys(RESOURCE_ALIASES), ...Object.values(RESOURCE_ALIASES)])
    for (const [prefix, count] of prefixFrequency) {
        if (count >= 2) {
            knownResources.add(prefix)
        }
    }
    const knownSorted = [...knownResources].sort((a, b) => b.split('-').length - a.split('-').length)

    function assign(name: string): { resource: string; method: string } {
        const override = TOOL_OVERRIDES[name]
        if (override) {
            return { resource: camelCase(aliasResource(override.resource)), method: override.method }
        }
        const { actionWord, baseSegs } = splitAction(name)
        // Longest known-resource prefix over baseSegs.
        for (const known of knownSorted) {
            const kSegs = known.split('-')
            if (
                kSegs.length <= baseSegs.length &&
                kSegs.every((s, i) => s === baseSegs[i]) &&
                // don't consume the entire base when there's no extra AND action exists
                true
            ) {
                const extra = baseSegs.slice(kSegs.length)
                const method = camelCase([...extra, actionWord].join('-'))
                return { resource: camelCase(aliasResource(known)), method }
            }
        }
        const resourceKebab = aliasResource(baseSegs.join('-') || name)
        return { resource: camelCase(resourceKebab), method: camelCase(actionWord) }
    }

    const resources = new Map<string, ResolvedMethod[]>()
    const usedMethodNames = new Map<string, Set<string>>()
    for (const t of tools) {
        const { resource, method } = assign(t.name)
        let methods = resources.get(resource)
        if (!methods) {
            methods = []
            resources.set(resource, methods)
            usedMethodNames.set(resource, new Set())
        }
        const used = usedMethodNames.get(resource)!
        let finalMethod = method
        if (used.has(finalMethod)) {
            // Disambiguate deterministically using the full tool tail.
            const { actionWord, baseSegs } = splitAction(t.name)
            finalMethod = camelCase(baseSegs.concat(actionWord).join('-'))
            let n = 2
            while (used.has(finalMethod)) {
                finalMethod = `${method}${n++}`
            }
            skipped.push({ name: t.name, reason: `method collision on ${resource}.${method} → renamed ${finalMethod}` })
        }
        used.add(finalMethod)

        const desc = toolDefs[t.name]?.description ?? ''
        const jsdoc = firstSentences(desc)
        const inputName = `${pascalCase(resource)}${pascalCase(finalMethod)}Params`
        methods.push({ method: finalMethod, tool: t, inputTypeName: inputName, inputRequired: false, jsdoc })
    }

    // --- Query wrapper tools → methods on the `query` resource ---
    // Kept out of the prefix-frequency pass so adding them can't re-shuffle the
    // resource assignment of previously generated tools.
    const wrapperTools = parseQueryWrappers(files)
    {
        let queryMethods = resources.get('query')
        if (!queryMethods) {
            queryMethods = []
            resources.set('query', queryMethods)
            usedMethodNames.set('query', new Set())
        }
        const used = usedMethodNames.get('query')!
        // `run` is the handwritten escape hatch on QueryBase.
        used.add('run')
        for (const w of wrapperTools) {
            if (used.has(w.methodName)) {
                throw new Error(`query wrapper method name collision: query.${w.methodName} (${w.name})`)
            }
            used.add(w.methodName)
            const jsdoc = firstSentences(toolDefs[w.name]?.description ?? '')
            const inputName = `Query${pascalCase(w.methodName)}Params`
            queryMethods.push({
                method: w.methodName,
                wrapper: w,
                inputTypeName: inputName,
                inputRequired: false,
                jsdoc,
            })
        }
    }

    // --- Build input types ---
    const inputBlocks: string[] = []
    for (const [resource, methods] of [...resources.entries()].sort()) {
        methods.sort((a, b) => a.method.localeCompare(b.method))
        for (const m of methods) {
            const { properties, required } = m.wrapper
                ? buildWrapperInputSchema(m.wrapper.schema)
                : buildInputSchema(m.tool!)
            const keys = Object.keys(properties)
            if (keys.length === 0) {
                m.inputTypeName = undefined
                continue
            }
            m.inputRequired = [...required].length > 0
            const objectSchema: JsonSchema = { type: 'object', properties, required: [...required] }
            inputBlocks.push(`export interface ${m.inputTypeName} ${renderObject(objectSchema, '')}\n`)
        }
    }

    // --- Emit files ---
    fs.mkdirSync(path.join(OUT_DIR, 'resources'), { recursive: true })
    emitSchemas()
    emitInputs(inputBlocks)
    const resourceNames = [...resources.keys()].sort()
    for (const resource of resourceNames) {
        emitResource(resource, resources.get(resource)!)
    }
    emitClient(resourceNames)

    // Format the emitted output so committed files match the generator's output
    // even after the repo's oxfmt pre-commit hook runs (no drift on re-generate).
    formatOutput()

    // Tools present in the definitions but not emitted through either path
    // (standard 1:1 handlers or query wrappers).
    const emitted = new Set([...tools.map((t) => t.name), ...wrapperTools.map((w) => w.name)])
    for (const toolName of Object.keys(toolDefs)) {
        if (!emitted.has(toolName)) {
            skipped.push({ name: toolName, reason: 'no inline handler object and no createQueryWrapper call' })
        }
    }

    // --- Summary ---
    const methodCount = [...resources.values()].reduce((a, m) => a + m.length, 0)
    const genuineSkips = skipped.filter((s) => !s.reason.startsWith('method collision'))
    const totalTools = Object.keys(toolDefs).length
    console.log('\n=== @posthog/sdk generation summary ===')
    console.log(`Total tools:    ${totalTools}`)
    console.log(`Tools emitted:  ${emitted.size} (${tools.length} handlers + ${wrapperTools.length} query wrappers)`)
    console.log(`Methods:        ${methodCount}`)
    console.log(`Resources:      ${resourceNames.length}`)
    console.log(`Coverage:       ${((emitted.size / totalTools) * 100).toFixed(1)}%`)
    console.log(`Skipped tools:  ${genuineSkips.length}`)
    const byReason = new Map<string, number>()
    for (const s of genuineSkips) {
        const key = s.reason.replace(/\d+/g, 'N')
        byReason.set(key, (byReason.get(key) ?? 0) + 1)
    }
    for (const [reason, count] of [...byReason.entries()].sort()) {
        console.log(`  - ${count}× ${reason}`)
    }
    if (genuineSkips.length > 0 && genuineSkips.length <= 60) {
        console.log(
            'Skipped:',
            genuineSkips
                .map((s) => s.name)
                .sort()
                .join(', ')
        )
    }
    const renames = skipped.filter((s) => s.reason.startsWith('method collision'))
    if (renames.length) {
        console.log(`Method renames (collisions): ${renames.length}`)
    }
}

function formatOutput(): void {
    const oxfmt = path.join(SDK_ROOT, 'node_modules/.bin/oxfmt')
    if (!fs.existsSync(oxfmt)) {
        console.warn('[generate] oxfmt not found — emitted files left unformatted')
        return
    }
    const files: string[] = []
    const walk = (dir: string): void => {
        for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
            const full = path.join(dir, entry.name)
            if (entry.isDirectory()) {
                walk(full)
            } else if (entry.name.endsWith('.ts')) {
                files.push(full)
            }
        }
    }
    walk(OUT_DIR)
    const result = spawnSync(oxfmt, files, { stdio: 'pipe', cwd: SDK_ROOT })
    if (result.status !== 0) {
        console.warn(`[generate] oxfmt exited ${result.status}: ${result.stderr?.toString().slice(0, 200)}`)
    }
}

function firstSentences(text: string): string {
    if (!text) {
        return ''
    }
    const match = /^(.*?[.!?])(\s|$)/.exec(text.trim())
    const s = match ? match[1]! : text.trim()
    return s.length > 300 ? s.slice(0, 297) + '...' : s
}

function banner(from: string): string {
    return `// AUTO-GENERATED by packages/sdk/scripts/generate.ts — do not edit.\n// Source: ${from}\n// Regenerate with: hogli build:openapi  (or: pnpm --filter=@posthog/sdk run generate)\n`
}

function emitSchemas(): void {
    const src = fs.readFileSync(SCHEMAS_SRC, 'utf8')
    // Replace the leading doc block with our banner; keep the namespace body.
    const nsIndex = src.indexOf('export namespace Schemas')
    const body = nsIndex >= 0 ? src.slice(nsIndex) : src
    const out = `${banner('services/mcp/src/api/generated.ts (Schemas namespace)')}\n/* eslint-disable */\n${body}`
    fs.writeFileSync(path.join(OUT_DIR, 'schemas.ts'), out)
}

function emitInputs(blocks: string[]): void {
    const out = `${banner('Orval Zod input schemas → JSON Schema → plain TS')}\n/* eslint-disable */\n\n${blocks.join('\n')}`
    fs.writeFileSync(path.join(OUT_DIR, 'inputs.ts'), out)
}

function emitResource(resource: string, methods: ResolvedMethod[]): void {
    methods.sort((a, b) => a.method.localeCompare(b.method))
    const className = `${pascalCase(resource)}Resource`
    const usedInputs = methods.map((m) => m.inputTypeName).filter((n): n is string => !!n)
    const inputImport = usedInputs.length
        ? `import type { ${[...new Set(usedInputs)].sort().join(', ')} } from '../inputs'\n`
        : ''
    const usesSchemas = methods.some((m) => m.tool && /\bSchemas\./.test(m.tool.responseType))
    const schemasImport = usesSchemas ? `import type { Schemas } from '../schemas'\n` : ''

    // Resources containing query-wrapper methods extend the handwritten
    // QueryBase (raw `run` escape hatch + wrapper runtime) instead of Resource.
    const hasWrappers = methods.some((m) => m.wrapper)
    const hasActors = methods.some((m) => m.wrapper && isActorsKind(m.wrapper.kind))
    const hasNonActors = methods.some((m) => m.wrapper && !isActorsKind(m.wrapper.kind))
    const queryTypeImports = [...(hasActors ? ['ActorsQueryResponse'] : []), ...(hasNonActors ? ['QueryResponse'] : [])]
    const baseImport = hasWrappers
        ? `import { QueryBase${queryTypeImports.length ? `, type ${queryTypeImports.join(', type ')}` : ''} } from '../../core/query'`
        : `import { Resource } from '../../core/resource'`
    const baseClass = hasWrappers ? 'QueryBase' : 'Resource'

    const methodTexts = methods.map((m) => emitMethod(m))
    const out = `${banner(`MCP tool handlers (resource: ${resource})`)}\n${baseImport}
import type { RequestOptions } from '../../core/config'
${schemasImport}${inputImport}
export class ${className} extends ${baseClass} {
${methodTexts.join('\n\n')}
}
`
    fs.writeFileSync(path.join(OUT_DIR, 'resources', `${resource}.ts`), out)
}

function isActorsKind(kind: string): boolean {
    return kind.endsWith('ActorsQuery')
}

function emitMethod(m: ResolvedMethod): string {
    if (m.wrapper) {
        return emitWrapperMethod(m, m.wrapper)
    }
    const t = m.tool!
    const resp = t.responseType
    const jsdoc = m.jsdoc ? `    /** ${escapeComment(m.jsdoc)} */\n` : ''
    // Prelude (scope resolution + body/query construction) is captured from the
    // handler at method-body depth (8 spaces) with transforms already applied.
    const prelude = t.preludeText

    // Inject `opts` into the request-arg object (before its closing brace).
    const argText = injectOpts(t.requestArgText)

    // Parameter signature.
    const usesParamsObject = /\bparams\b/.test(prelude + ' ' + argText)
    let paramSig: string
    if (m.inputTypeName) {
        paramSig = m.inputRequired
            ? `params: ${m.inputTypeName}, opts?: RequestOptions`
            : `params: ${m.inputTypeName} = {}, opts?: RequestOptions`
    } else if (usesParamsObject) {
        // Fallback for handlers that pass the whole params object opaquely.
        paramSig = `params: Record<string, unknown> = {}, opts?: RequestOptions`
    } else {
        paramSig = `opts?: RequestOptions`
    }

    const lines = [`${jsdoc}    async ${m.method}(${paramSig}): Promise<${resp}> {`]
    if (prelude) {
        lines.push(prelude)
    }
    lines.push(`        return this.http.request<${resp}>(${argText})`)
    lines.push('    }')
    return lines.join('\n')
}

function emitWrapperMethod(m: ResolvedMethod, w: WrapperTool): string {
    const jsdoc = m.jsdoc ? `    /** ${escapeComment(m.jsdoc)} */\n` : ''
    const actors = isActorsKind(w.kind)
    const resp = actors ? 'ActorsQueryResponse' : 'QueryResponse'
    const runner = actors ? 'runActorsWrapped' : 'runWrapped'
    const paramSig = m.inputTypeName
        ? m.inputRequired
            ? `params: ${m.inputTypeName}, opts?: RequestOptions`
            : `params: ${m.inputTypeName} = {}, opts?: RequestOptions`
        : `params: Record<string, unknown> = {}, opts?: RequestOptions`
    return [
        `${jsdoc}    async ${m.method}(${paramSig}): Promise<${resp}> {`,
        `        return this.${runner}<${resp}>(${JSON.stringify(w.kind)}, params, opts)`,
        `    }`,
    ].join('\n')
}

/** Append `opts,` as the last property of the request-arg object literal. */
function injectOpts(argText: string): string {
    const lastBrace = argText.lastIndexOf('}')
    const head = argText.slice(0, lastBrace).replace(/\s*$/, '')
    const tail = argText.slice(lastBrace)
    const sep = head.endsWith(',') || head.endsWith('{') ? '' : ','
    return `${head}${sep}\n            opts,\n        ${tail}`
}

function emitClient(resourceNames: string[]): void {
    const imports = resourceNames.map((r) => `import { ${pascalCase(r)}Resource } from './resources/${r}'`).join('\n')
    const fields = resourceNames.map((r) => `    readonly ${r}: ${pascalCase(r)}Resource`).join('\n')
    const inits = resourceNames.map((r) => `        this.${r} = new ${pascalCase(r)}Resource(http, scope)`).join('\n')
    const out = `${banner('composed from resources/*')}\nimport type { HttpClient } from '../core/http'
import type { ScopeResolver } from '../core/scope'
${imports}

/** The PostHog management API surface, one property per resource. */
export class PostHogClient {
${fields}

    constructor(http: HttpClient, scope: ScopeResolver) {
${inits}
    }
}
`
    fs.writeFileSync(path.join(OUT_DIR, 'client.ts'), out)
}

main()
